-- ==========================================================
-- 60_update_from_excel.sql
-- 엑셀 원본 데이터로 역량 점수 업데이트 + 백분위 status 재계산
-- ==========================================================

SET search_path TO idino_career, public;

BEGIN;

-- 1. 임시 테이블 생성 및 엑셀 데이터 로드
CREATE TEMP TABLE tmp_excel_scores (
    student_id VARCHAR(20),
    competency_cd VARCHAR(20),
    current_score DECIMAL(10,2)
);


-- Loaded 17178 records from Excel

-- 2. 엑셀 데이터로 점수 업데이트 (매칭되는 student_id+competency_cd만)
UPDATE tb_student_competency sc
SET
    current_score = e.current_score,
    gap_score     = e.current_score - sc.target_score,
    upd_user_id   = 'EXCEL_IMPORT',
    upd_dt        = CURRENT_TIMESTAMP
FROM tmp_excel_scores e
WHERE sc.student_id    = e.student_id
  AND sc.competency_cd = e.competency_cd;

-- 3. 동일학과 백분위 기반 status 재계산 (전체 학생)
WITH dept_percentiles AS (
    SELECT
        sc.student_competency_id,
        PERCENT_RANK() OVER (
            PARTITION BY s.department_cd, sc.competency_cd
            ORDER BY sc.current_score
        ) AS pct_rank
    FROM tb_student_competency sc
    JOIN tb_student s ON sc.student_id = s.student_id
    JOIN tb_competency c ON sc.competency_cd = c.competency_cd AND c.use_fg = 'Y'
)
UPDATE tb_student_competency sc
SET
    status = CASE
        WHEN dp.pct_rank >= 0.75 THEN 'excellent'
        WHEN dp.pct_rank >= 0.50 THEN 'good'
        WHEN dp.pct_rank >= 0.25 THEN 'average'
        ELSE 'needs_improvement'
    END,
    upd_user_id = 'SYSTEM_RECALC',
    upd_dt      = CURRENT_TIMESTAMP
FROM dept_percentiles dp
WHERE sc.student_competency_id = dp.student_competency_id;

DROP TABLE tmp_excel_scores;

COMMIT;
